void BaseAgent::Attack()
{
///<<< BEGIN WRITING YOUR CODE Attack
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return;

	//LordLogDebug("===BaseAgent(%d)===Attack enter", pCreature->entityId);
	if (pCreature->getCurrentTargetEntityId() <= 0) {
		pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_MOVE);
		return;
	}

	if (pCreature->getAttackCd() > 0) {
		return;
	}

	if (pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_DEATH)
	{
		return;
	}

	Entity* entity = Server::Instance()->getWorld()->getEntity(pCreature->getCurrentTargetEntityId());
	if (!entity) {
		return;
	}

	if (!pCreature->entityInAttackRange(entity)) {
		pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_MOVE);
		return;
	}

	//停止寻路
	pCreature->setPathToEntity(nullptr);

	//LordLogDebug("===BaseAgent(%d)===Attack do", pCreature->entityId);
	EntityPlayer* targetPlayer = dynamic_cast<EntityPlayer*>(entity);
	EntityCreatureAI* targetCreature = dynamic_cast<EntityCreatureAI*>(entity);
	if (targetPlayer)
	{
		pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_ATTACK);
		pCreature->attackPerformance(targetPlayer);
		pCreature->setAttackCd();

		//pPlayer dead  process
		if (targetPlayer->isDead)
		{
			if (pCreature->getCurrentTargetEntityId() == targetPlayer->entityId)
			{
				pCreature->setCurrentTargetEntityId(0, false);
				pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_MOVE);
			}
		}
	} 
	else if (targetCreature)
	{
		pCreature->attackPerformance(targetCreature);
		pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_ATTACK);
		pCreature->setAttackCd();
		targetCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_BE_OTHER_ATTACK);
	}
	
///<<< END WRITING YOUR CODE
}

void BaseAgent::BossFreeSkill()
{
///<<< BEGIN WRITING YOUR CODE BossFreeSkill
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return;
	if (pCreature->isBoss() && pCreature->getFreeSkillCd() <= 0)
	{
		EntityArr pPlayers = Server::Instance()->getWorld()->getClosestCreatureBossToPlayer(pCreature, pCreature->getSkillDistance());
		for (int j = 0; j < int(pPlayers.size()); ++j)
		{
			EntityPlayer* pPlayer = dynamic_cast<EntityPlayer*>(pPlayers[j]);
			if (pPlayer)
			{
				if (pCreature->isCanAttackEntityBySkill(pPlayer))
				{
					pCreature->attackPerformance(pPlayer);
				}
			}
		}
		pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_ATTACK);
		pCreature->setFreeSkillCd();
		pCreature->groupAttackPerformance();
	}
///<<< END WRITING YOUR CODE
}

bool BaseAgent::FindEnemy()
{
///<<< BEGIN WRITING YOUR CODE FindEnemy
	//行尸走肉专用

	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	NULL_RETURN(pCreature, false);

	//LordLogDebug("===BaseAgent(%d)===FindTarget enter", pCreature->entityId);
	if (pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_ATTACK
		|| pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_DEATH) {
		return true;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->getUpdateTargetCd() > 0) {
		return true;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->isRevengingTarget()) {
		return true;
	}

	//LordLogDebug("===BaseAgent(%d)===FindTarget do", pCreature->entityId);
	pCreature->setUpdateTargetCd();

	/*if (!SCRIPT_EVENT::FindTargetEvent::invoke(pCreature->entityId))
	{
		return;
	}*/

	bool findPlayerTargetSucc = pCreature->findCloestPlayerTargetInPatrolDist();
	if (!findPlayerTargetSucc)
	{
		//巡逻回场
		auto pWalkingDead = dynamic_cast<EntityWalkingDeadAI*>(pCreature);
		auto curPos = pWalkingDead->getPosition();
		if (pWalkingDead && !pWalkingDead->isWithinHomeDistanceFromPosition(BlockPos(curPos.x, curPos.y, curPos.z)))
		{
			pWalkingDead->doGoHome();
		}
		else
		{
			doPatrolState();
		}
	}

	return true;
///<<< END WRITING YOUR CODE
}

void BaseAgent::FindTarget()
{
///<<< BEGIN WRITING YOUR CODE FindTarget
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	NULL_RETURN_VOID(pCreature);

	//LordLogDebug("===BaseAgent(%d)===FindTarget enter", pCreature->entityId);
	if (pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_ATTACK) {
		return;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->getUpdateTargetCd() > 0) {
		return;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->isRevengingTarget()) {
		return;
	}

	//LordLogDebug("===BaseAgent(%d)===FindTarget do", pCreature->entityId);
	pCreature->setUpdateTargetCd();

	if (!SCRIPT_EVENT::FindTargetEvent::invoke(pCreature->entityId))
	{
		return;
	}

	bool findPlayerTargetSucc = pCreature->findCloestPlayerTargetInPatrolDist();
	if (!findPlayerTargetSucc)
	{
		EntityArr BaseEntitys = Server::Instance()->getWorld()->getEntityCreatureBaseAI();
		if (BaseEntitys.size() == 1 && BaseEntitys[0])
		{
			pCreature->setCurrentTargetEntityId(BaseEntitys[0]->entityId, false);
		}
	}
///<<< END WRITING YOUR CODE
}

behaviac::EBTStatus BaseAgent::findTargetPlayer()
{
///<<< BEGIN WRITING YOUR CODE findTargetPlayer
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return behaviac::EBTStatus::BT_FAILURE;


	auto player = pCreature->findTargetPlayer();
	if (!player || !SCRIPT_EVENT::BirdSimulator_MonsterFindPlayerEvent::invoke(pCreature->entityId, player->getPlatformUserId()) || player->isLogout())
	{
		pCreature->setCurrentTargetEntityId(0, false);
		return behaviac::EBTStatus::BT_FAILURE;
	}

	
	if (pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_ATTACK) {
		return behaviac::EBTStatus::BT_SUCCESS;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->getUpdateTargetCd() > 0) {

		return behaviac::EBTStatus::BT_SUCCESS;
	}

	if (pCreature->getCurrentTargetEntityId() >= 0 && pCreature->isRevengingTarget()) {
		return behaviac::EBTStatus::BT_SUCCESS;
	}

	if (player)
	{
		pCreature->setCurrentTargetEntityId(player->entityId, false);
		pCreature->setUpdateTargetCd();
		return behaviac::EBTStatus::BT_SUCCESS;
	}
	
	return behaviac::EBTStatus::BT_FAILURE;
///<<< END WRITING YOUR CODE
}

void BaseAgent::gotoHome()
{
///<<< BEGIN WRITING YOUR CODE gotoHome
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return;
	
	if (pCreature->getPosition().distanceTo(pCreature->getHomePosition()) <= 2)
	{
		SCRIPT_EVENT::BirdSimulator_MonsterDieEvent::invoke(pCreature->entityId);
		return;
	}

	if (pCreature->getUpdatePathCd(-1000) > 0)
	{
		return;
	}
	else
	{
		pCreature->getPathToHome(LogicSetting::Instance()->checkGameType(ClientGameType::WalkingDead) ? 50.0F : 256.0F);
		pCreature->setUpdatePathCd(-1000);
	}
	
	pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_MOVE);

///<<< END WRITING YOUR CODE
}

