void BaseAgent::Move()
{
///<<< BEGIN WRITING YOUR CODE Move
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return;

	//LordLogDebug("===BaseAgent(%d)===Move enter", pCreature->entityId);

	if (pCreature->getCurrentTargetEntityId() <= 0
		|| pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_ATTACK 
		|| pCreature->getCreatureAction() == CreatureActionState::CREATURE_AS_DEATH)
	{
		return;
	}

	Entity* entity = Server::Instance()->getWorld()->getEntity(pCreature->getCurrentTargetEntityId());
	if (!entity) {
		return;
	}

	if (LogicSetting::Instance()->checkGameType({ ClientGameType::LiftingSimulator, ClientGameType::LSChampionShip }))
	{
		pCreature->directMoveToPos(entity->getWidelyPos(), true);
	}
	else
	{
		if (pCreature->getUpdatePathCd(entity->entityId) > 0) {
			return;
		}

		if (pCreature->entityInAttackRange(entity)) {
			pCreature->setPathToEntity(nullptr);
			return;
		}

		//LordLogDebug("===BaseAgent(%d)===Move do", pCreature->entityId);
		pCreature->setUpdatePathCd(entity->entityId);
		pCreature->getPathToEntity(entity, LogicSetting::Instance()->checkGameType(ClientGameType::WalkingDead) ? 50.0F : 256.0F);
	}

	pCreature->changeCreatureAction(CreatureActionState::CREATURE_AS_MOVE);

	SCRIPT_EVENT::ChaseStateEvent::invoke(pCreature->entityId);
	
///<<< END WRITING YOUR CODE
}

void BaseAgent::MultipleAttack()
{
///<<< BEGIN WRITING YOUR CODE MultipleAttack
	EntityCreatureAI* pCreature = dynamic_cast<EntityCreatureAI*>(getEntity());
	if (!pCreature)
		return;
	if (pCreature->getAttackCd() > 0)
		return;
	EntityArr targets = pCreature->getClosestPlayers();
	if (targets.size() > size_t(0))
	{
		for (int j = 0; j < int(targets.size()); ++j)
		{
			EntityPlayer* pPlayer = dynamic_cast<EntityPlayer*>(targets[j]);
			if (pPlayer)
			{
				pCreature->attackPerformance(pPlayer);
			}
		}
		pCreature->setAttackCd();
		pCreature->changeCreatureAction(CREATURE_AS_ATTACK);
	}
	else
	{
		pCreature->setSmallAttackCd();
		pCreature->changeCreatureAction(CREATURE_AS_IDLE);
	}
///<<< END WRITING YOUR CODE
}


